import { setup, assign, emit } from 'xstate';

interface AuditContext {
  userId: string;
  actions: number;
}

type AuditEvent =
  | { type: 'LOGIN' }
  | { type: 'LOGOUT' }
  | { type: 'ACTION'; name: string };

type AuditEmitted =
  | { type: 'audit'; kind: 'login'; userId: string }
  | { type: 'audit'; kind: 'logout'; userId: string }
  | { type: 'audit'; kind: 'action'; userId: string; name: string };

