`fromCallback` creates an actor from an imperative setup function. You get `sendBack` to push events to the parent and `receive` to react to events the parent sends you. The return value is a cleanup function that runs when the actor stops — use it to remove listeners, close sockets, or clear timers.

```ts
import { setup, fromCallback, assign } from 'xstate';

type PortEvent = { type: 'DATA'; payload: unknown };
type InEvent = { type: 'SEND'; payload: unknown };

const portActor = fromCallback<InEvent, { port: MessagePort }>(
  ({ input, sendBack, receive }) => {
    const onMessage = (ev: MessageEvent) => {
      sendBack({ type: 'DATA', payload: ev.data });
    };
    input.port.addEventListener('message', onMessage);
    input.port.start();
    receive((ev) => {
      if (ev.type === 'SEND') input.port.postMessage(ev.payload);
    });
    return () => {
      input.port.removeEventListener('message', onMessage);
      input.port.close();
    };
  }
);

export const portMachine = setup({
  types: {
    context: {} as { port: MessagePort; last: unknown },
    events: {} as PortEvent,
    input: {} as { port: MessagePort },
  },
  actors: { portActor },
}).createMachine({
  id: 'port',
  context: ({ input }) => ({
    port: input.port,
    last: null,
  }),
  invoke: {
    src: 'portActor',
    input: ({ context }) => ({ port: context.port }),
  },
  on: {
    DATA: {
      actions: assign({ last: ({ event }) => event.payload }),
    },
  },
});
```

