import { setup, fromPromise, assign } from 'xstate';

export class AppError extends Error {
  constructor(readonly code: string, message: string) {
    super(message);
    this.name = 'AppError';
  }
}

type Context = { code?: string; message?: string };
type Events = { type: 'GO' } | { type: 'RETRY' };

const load = fromPromise<string, undefined>(async () => {
  throw new AppError('E_LOAD', 'no');
});

export const m = setup({
  types: {
    context: {} as Context,
    events: {} as Events,
  },
  actions: {
    captureError: assign(({ event }) => {
      const err = (event as { error?: unknown }).error;
      if (err instanceof AppError) {
        return { code: err.code, message: err.message };
      }
      return {
        code: 'E_UNKNOWN',
        message: err instanceof Error ? err.message : String(err),
      };
    }),
  },
  actors: { load },
}).createMachine({
  id: 'm',
  context: {},
  initial: 'idle',
  states: {
    idle: { on: { GO: 'work' } },
    work: {
      invoke: {
        src: 'load',
        onDone: 'ok',
        onError: { target: 'bad', actions: 'captureError' },
      },
    },
    ok: { type: 'final' },
    bad: {
      on: { RETRY: 'work' },
    },
  },
});
```

When an invoked actor rejects (for `fromPromise`) or throws (for other actor logics), XState raises a special error event on the invoking state. You handle it with the `onError` transition: it carries `event.error` typed as `unknown` (narrow with `instanceof Error`), and you typically move to a dedicated `failed` state while assigning a typed error into context. `onError` pairs with `onDone` on the same invocation, and both have access to the same typed `event.output`/`event.error` shape the actor declared.

```ts
import { setup, fromPromise, assign } from 'xstate';

type Order = { id: string; total: number };
type Context = { cartId: string; order?: Order; error?: string };
type Events = { type: 'CHECKOUT'; cartId: string } | { type: 'RETRY' };

const placeOrder = fromPromise<Order, { cartId: string }>(async ({ input }) => {
  const res = await fetch(`/api/cart/${input.cartId}/checkout`, { method: 'POST' });
  if (!res.ok) throw new Error(`checkout failed: ${res.status}`);
  return (await res.json()) as Order;
});

export const checkoutMachine = setup({
  types: {
    context: {} as Context,
    events: {} as Events,
  },
  actors: { placeOrder },
}).createMachine({
  id: 'checkout',
  context: { cartId: '' },
  initial: 'idle',
  states: {
    idle: {
      on: {
        CHECKOUT: {
          target: 'placing',
          actions: assign({ cartId: ({ event }) => event.cartId }),
        },
      },
    },
    placing: {
      invoke: {
        src: 'placeOrder',
        input: ({ context }) => ({ cartId: context.cartId }),
        onDone: {
          target: 'placed',
          actions: assign({ order: ({ event }) => event.output }),
        },
        onError: {
          target: 'failed',
          actions: assign({
            error: ({ event }) =>
              event.error instanceof Error
                ? event.error.message
                : String(event.error),
          }),
        },
      },
    },
    placed: { type: 'final' },
    failed: {
      on: { RETRY: 'placing' },
    },
  },
});
```

```ts
import { setup, fromPromise, assign } from 'xstate';

type UploadError =
  | { kind: 'network' }
  | { kind: 'server'; status: number }
  | { kind: 'unknown'; message: string };

type Context = {
  file?: File;
  url?: string;
  error?: UploadError;
};
type Events =
  | { type: 'UPLOAD'; file: File }
  | { type: 'RETRY' }
  | { type: 'CANCEL' };

const upload = fromPromise<{ url: string }, { file: File }>(
  async ({ input }) => {
    let res: Response;
    try {
      const body = new FormData();
      body.append('file', input.file);
      res = await fetch('/api/upload', { method: 'POST', body });
    } catch {
      throw { kind: 'network' } satisfies UploadError;
    }
    if (!res.ok) {
      throw { kind: 'server', status: res.status } satisfies UploadError;
    }
    return (await res.json()) as { url: string };
  }
);

function toUploadError(err: unknown): UploadError {
  if (
    typeof err === 'object' &&
    err !== null &&
    'kind' in err &&
    typeof (err as { kind: unknown }).kind === 'string'
  ) {
    return err as UploadError;
  }
  return {
    kind: 'unknown',
    message: err instanceof Error ? err.message : String(err),
  };
}

export const uploadMachine = setup({
  types: {
    context: {} as Context,
    events: {} as Events,
  },
  actors: { upload },
}).createMachine({
  id: 'upload',
  context: {},
  initial: 'idle',
  states: {
    idle: {
      on: {
        UPLOAD: {
          target: 'uploading',
          actions: assign({
            file: ({ event }) => event.file,
            error: undefined,
          }),
        },
      },
    },
    uploading: {
      invoke: {
        src: 'upload',
        input: ({ context }) => ({ file: context.file as File }),
        onDone: {
          target: 'done',
          actions: assign({ url: ({ event }) => event.output.url }),
        },
        onError: {
          target: 'failed',
          actions: assign({
            error: ({ event }) => toUploadError(event.error),
          }),
        },
      },
      on: { CANCEL: 'idle' },
    },
    done: { type: 'final' },
    failed: {
      on: {
        RETRY: 'uploading',
        CANCEL: 'idle',
      },
    },
  },
});
```

