type Ctx = {
  city: string;
  data: Weather | null;
  error: string | null;
};

type Ev =
  | { type: 'FETCH'; city: string }
  | { type: 'RETRY' }
  | { type: 'RESET' };

const loadWeather = fromPromise<Weather, { city: string }>(async ({ input }) => {
  const res = await fetch(`/api/weather?city=${encodeURIComponent(input.city)}`);
  if (!res.ok) throw new Error(`status ${res.status}`);
  return (await res.json()) as Weather;
});

export const weatherMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { loadWeather },
}).createMachine({
  id: 'weather',
  initial: 'idle',
  context: { city: '', data: null, error: null },
  states: {
    idle: {
      on: {
        FETCH: {
          target: 'loading',
          actions: assign({ city: ({ event }) => event.city }),
        },
      },
    },
    loading: {
      invoke: {
        src: 'loadWeather',
        input: ({ context }) => ({ city: context.city }),
        onDone: {
          target: 'success',
          actions: assign({ data: ({ event }) => event.output }),
        },
        onError: {
          target: 'failure',
          actions: assign({
            error: ({ event }) =>
              event.error instanceof Error ? event.error.message : 'failed',
          }),
        },
      },
    },
    success: { on: { RESET: 'idle' } },
    failure: { on: { RETRY: 'loading', RESET: 'idle' } },
  },
});
