An invoked machine in XState v5 runs as a child actor for the lifetime of its parent state. The child is declared with its own `setup()` and typed `input`/`output`. Register it in the parent's `setup.actors` so it can be referenced by name. When the child reaches its final state, the parent's `onDone` fires with `event.output` carrying the child's declared output type.

```ts
import { setup, assign } from 'xstate';

type PinInput = { required: number };
type PinOutput = { pin: string };

const pinMachine = setup({
  types: {
    input: {} as PinInput,
    context: {} as { required: number; entered: string },
    events: {} as
      | { type: 'DIGIT'; value: string }
      | { type: 'SUBMIT' },
    output: {} as PinOutput,
  },
}).createMachine({
  id: 'pin',
  initial: 'entering',
  context: ({ input }) => ({ required: input.required, entered: '' }),
  states: {
    entering: {
      on: {
        DIGIT: {
          actions: assign({
            entered: ({ context, event }) => context.entered + event.value,
          }),
        },
        SUBMIT: {
          guard: ({ context }) => context.entered.length === context.required,
          target: 'done',
        },
      },
    },
    done: { type: 'final' },
  },
  output: ({ context }) => ({ pin: context.entered }),
});

type LockCtx = { pin: string | null };
type LockEv = { type: 'UNLOCK' };

export const lockMachine = setup({
  types: { context: {} as LockCtx, events: {} as LockEv },
  actors: { pinMachine },
}).createMachine({
  id: 'lock',
  initial: 'locked',
  context: { pin: null },
  states: {
    locked: { on: { UNLOCK: 'prompting' } },
    prompting: {
      invoke: {
        src: 'pinMachine',
        input: () => ({ required: 4 }),
        onDone: {
          target: 'unlocked',
          actions: assign({ pin: ({ event }) => event.output.pin }),
        },
      },
    },
    unlocked: {},
  },
});
```

