const slot = setup({
  types: {
    context: {} as { filled: boolean },
    events: {} as { type: 'FILL' },
  },
}).createMachine({
  id: 'slot',
  context: { filled: false },
  on: {
    FILL: { actions: assign({ filled: true }) },
  },
});

type SlotRef = ActorRefFrom<typeof slot>;

