  types: {
    context: {} as { subs: Record<string, SubRef>; receipts: number },
    events: {} as
      | { type: 'SUBSCRIBE'; id: string }
      | { type: 'PUBLISH'; topic: string }
      | { type: 'RECEIPT'; topic: string },
  },
  actors: { subscriber },
