```ts
import { setup, assign } from 'xstate';

type CartItem = { id: string; price: number };
type CheckoutContext = { cart: CartItem[]; total: number };
type CheckoutEvent =
  | { type: 'ADD'; item: CartItem }
  | { type: 'REMOVE'; id: string }
  | { type: 'SUBMIT' };

export const checkoutMachine = setup({
  types: {
    context: {} as CheckoutContext,
    events: {} as CheckoutEvent,
  },
  guards: {
    isEmpty: ({ context }) => context.total === 0,
  },
}).createMachine({
  id: 'checkout',
  initial: 'reviewing',
  context: { cart: [], total: 0 },
  states: {
    reviewing: {
      always: [
        { guard: 'isEmpty', target: 'empty' },
      ],
      on: {
        ADD: {
          actions: assign({
            cart: ({ context, event }) => [...context.cart, event.item],
            total: ({ context, event }) => context.total + event.item.price,
          }),
        },
        REMOVE: {
          actions: assign({
            cart: ({ context, event }) => context.cart.filter((i) => i.id !== event.id),
            total: ({ context, event }) => {
              const removed = context.cart.find((i) => i.id === event.id);
              return removed ? context.total - removed.price : context.total;
            },
          }),
        },
        SUBMIT: { target: 'submitted' },
      },
    },
    empty: {
      on: {
        ADD: {
          target: 'reviewing',
          actions: assign({
            cart: ({ event }) => [event.item],
            total: ({ event }) => event.item.price,
          }),
        },
      },
    },
    submitted: { type: 'final' },
  },
});
```

Convert this XState v4 machine to v5 using setup().createMachine. It uses v4 transient states with cond which is what `always` replaces:

```js
import { Machine, assign } from 'xstate';

const traffic = Machine({
  id: 'traffic',
  initial: 'evaluating',
  context: { cars: 0 },
  states: {
    evaluating: {
      on: {
        '': [
          { target: 'green', cond: (ctx) => ctx.cars > 5 },
          { target: 'red' }
        ]
      }
    },
    green: { on: { TICK: 'evaluating' } },
    red: { on: { TICK: 'evaluating' } }
  }
});
```

```ts
