Use `always`: an array of transitions evaluated whenever the state is entered or the context changes. Whichever guard hits first fires, with no event needed.

```ts
import { setup, assign } from 'xstate';

type Ctx = { filled: number; required: number };
type Ev = { type: 'FILL'; amount: number };

export const fillup = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  guards: {
    isFull: ({ context }) => context.filled >= context.required,
  },
}).createMachine({
  id: 'fillup',
  initial: 'filling',
  context: { filled: 0, required: 100 },
  states: {
    filling: {
      always: [
        { guard: 'isFull', target: 'done' },
      ],
      on: {
        FILL: {
          actions: assign({
            filled: ({ context, event }) => context.filled + event.amount,
          }),
        },
      },
    },
    done: { type: 'final' },
  },
});
```

```ts
import { setup, assign } from 'xstate';

type OrderStatus = 'pending' | 'paid' | 'cancelled';

type OrderContext = {
  id: string;
  status: OrderStatus;
};

type OrderEvent =
  | { type: 'SET_STATUS'; status: OrderStatus }
  | { type: 'SHIP' }
  | { type: 'REOPEN' };

export const orderMachine = setup({
  types: {
    context: {} as OrderContext,
    events: {} as OrderEvent,
  },
  guards: {
    isPaid: ({ context }) => context.status === 'paid',
    isCancelled: ({ context }) => context.status === 'cancelled',
  },
}).createMachine({
  id: 'order',
  initial: 'review',
  context: { id: '', status: 'pending' },
  states: {
    review: {
      always: [
        { guard: 'isCancelled', target: 'cancelled' },
        { guard: 'isPaid', target: 'fulfilling' },
      ],
      on: {
        SET_STATUS: {
          actions: assign({ status: ({ event }) => event.status }),
        },
      },
    },
    fulfilling: {
      on: { SHIP: { target: 'shipped' } },
    },
    shipped: { type: 'final' },
    cancelled: {
      on: {
        REOPEN: {
          target: 'review',
          actions: assign({ status: 'pending' as const }),
        },
      },
    },
  },
});
```

`always` is a list of eventless (transient) transitions. They are evaluated as soon as the state is entered and again every time the context is updated by an action in that state. Each entry is a normal transition object with an optional `guard` and a `target`; the first entry whose guard passes fires. If no guard passes, the state remains active and waits for a real event. Use `always` to keep derived/computed-state decisions in the machine itself rather than deciding in the caller.

```ts
import { setup, assign } from 'xstate';

type GateContext = { attempts: number };
type GateEvent = { type: 'TRY' };

export const gateMachine = setup({
  types: {
    context: {} as GateContext,
    events: {} as GateEvent,
  },
  guards: {
    tooManyAttempts: ({ context }) => context.attempts >= 3,
  },
}).createMachine({
  id: 'gate',
  initial: 'open',
  context: { attempts: 0 },
  states: {
    open: {
      always: [
        { guard: 'tooManyAttempts', target: 'locked' },
      ],
      on: {
        TRY: {
          actions: assign({
            attempts: ({ context }) => context.attempts + 1,
          }),
        },
      },
    },
    locked: { type: 'final' },
  },
});
```

