v5 renames the transient-transition slot from `on: { '': [...] }` to a top-level `always: [...]` on the state. Guards use the `guard` key (not `cond`) and are typically referenced by name via `setup.guards`.

```ts
import { setup } from 'xstate';

type Ctx = { token: string | null };
type Ev = { type: 'LOAD' };

export const boot = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  guards: {
    hasToken: ({ context }) => context.token !== null,
  },
}).createMachine({
  id: 'boot',
  initial: 'checking',
  context: { token: null },
  states: {
    checking: {
      always: [
        { guard: 'hasToken', target: 'authed' },
        { target: 'login' },
      ],
    },
    authed: { type: 'final' },
    login: {
      on: { LOAD: { target: 'checking' } },
    },
  },
});
```

