type VoteContext = { a: number; b: number; winner: 'a' | 'b' | null };
type VoteEvent =
  | { type: 'VOTE_A' }
  | { type: 'VOTE_B' };

export const voteMachine = setup({
  types: {
    context: {} as VoteContext,
    events: {} as VoteEvent,
  },
  guards: {
    aWon: ({ context }) => context.a >= 10,
    bWon: ({ context }) => context.b >= 10,
  },
}).createMachine({
  id: 'vote',
  initial: 'open',
  context: { a: 0, b: 0, winner: null },
  states: {
    open: {
      always: [
        { guard: 'aWon', target: 'winner', actions: assign({ winner: 'a' as const }) },
        { guard: 'bWon', target: 'winner', actions: assign({ winner: 'b' as const }) },
      ],
      on: {
        VOTE_A: { actions: assign({ a: ({ context }) => context.a + 1 }) },
