          actions: ['storeQuery', 'rescheduleSearch'],
        },
      },
    },
    debouncing: {
      on: {
        INPUT: {
          target: 'debouncing',
          reenter: true,
          actions: ['cancelSearch', 'storeQuery', 'rescheduleSearch'],
        },
        SEARCH: { target: 'searching' },
      },
    },
    searching: {
      on: {
        RESULTS: {
          target: 'idle',
          actions: 'storeResults',
