import { setup, assign, raise, cancel } from 'xstate';

type Toast = { id: string; message: string };
type ToastContext = { queue: Toast[] };
type ToastEvent =
  | { type: 'ENQUEUE'; toast: Toast }
  | { type: 'DISMISS' }
  | { type: 'EXPIRE' };

export const toastQueue = setup({
  types: {
    context: {} as ToastContext,
    events: {} as ToastEvent,
  },
  actions: {
    enqueue: assign({
      queue: ({ context, event }) =>
        event.type === 'ENQUEUE'
          ? [...context.queue, event.toast]
          : context.queue,
    }),
    shift: assign({
      queue: ({ context }) => context.queue.slice(1),
    }),
    scheduleExpire: raise(
      { type: 'EXPIRE' },
      { id: 'activeToast', delay: 4000 },
    ),
    cancelExpire: cancel('activeToast'),
  },
  guards: {
    hasToast: ({ context }) => context.queue.length > 0,
  },
}).createMachine({
  id: 'toastQueue',
  initial: 'idle',
  context: { queue: [] },
  states: {
    idle: {
      always: [
        { guard: 'hasToast', target: 'showing' },
      ],
      on: {
        ENQUEUE: { actions: 'enqueue' },
      },
    },
    showing: {
      entry: 'scheduleExpire',
      exit: 'cancelExpire',
      on: {
        DISMISS: {
          target: 'idle',
          actions: 'shift',
        },
        EXPIRE: {
          target: 'idle',
          actions: 'shift',
        },
        ENQUEUE: { actions: 'enqueue' },
      },
    },
  },
});
