type Ev =
  | { type: 'ADD'; item: string }
  | { type: 'FINALIZE' };
type Out = { items: string[]; count: number };

export const listMachine = setup({
  types: {
    context: {} as Ctx,
    events: {} as Ev,
    output: {} as Out,
  },
}).createMachine({
  id: 'list',
  initial: 'collecting',
  context: { items: [] },
  states: {
    collecting: {
      on: {
        ADD: {
          actions: assign({
            items: ({ context, event }) => [...context.items, event.item],
          }),
        },
        FINALIZE: 'done',
      },
    },
    done: { type: 'final' },
  },
  output: ({ context }) => ({
    items: context.items,
    count: context.items.length,
