  types: {
    context: {} as Ctx,
    events: {} as Ev,
  },
}).createMachine({
  id: 'counter',
  initial: 'ready',
  context: { count: 0, lastEvent: '' },
  states: {
    ready: {
      on: {
        BUMP: {
          actions: assign({
            count: ({ context, event }) => context.count + event.by,
            lastEvent: ({ event }) => event.type,
          }),
        },
        RESET: {
          actions: assign({ count: 0, lastEvent: 'RESET' }),
        },
      },
    },
  },
});
