  | { type: 'SHUTDOWN' };

const moderator = setup({
  types: {
    context: {} as { checked: number },
    events: {} as ModeratorEvent,
  },
}).createMachine({
  id: 'moderator',
  initial: 'ready',
  context: { checked: 0 },
  states: {
    ready: {
      on: {
        CHECK: [
          {
            guard: ({ event }) => !event.text.includes('spam'),
            actions: [
              assign({ checked: ({ context }) => context.checked + 1 }),
              sendTo(({ self }) => self._parent!, ({ event }) => ({
                type: 'APPROVED' as const,
                text: event.text,
              })),
            ],
          },
          {
            actions: [
              assign({ checked: ({ context }) => context.checked + 1 }),
              sendTo(({ self }) => self._parent!, ({ event }) => ({
                type: 'REJECTED' as const,
                reason: `blocked: ${event.text}`,
              })),
            ],
          },
        ],
        SHUTDOWN: 'off',
      },
    },
    off: { type: 'final' },
  },
});

type RoomEvent =
  | { type: 'POST'; text: string }
  | { type: 'APPROVED'; text: string }
  | { type: 'REJECTED'; reason: string }
  | { type: 'CLOSE' };

export const chatRoom = setup({
  types: {
    context: {} as { approved: string[]; rejected: string[] },
    events: {} as RoomEvent,
  },
  actors: { moderator },
}).createMachine({
  id: 'room',
  context: { approved: [], rejected: [] },
  invoke: { id: 'mod', src: 'moderator' },
  initial: 'open',
  states: {
    open: {
      on: {
        POST: {
          actions: sendTo('mod', ({ event }) => ({
            type: 'CHECK' as const,
            text: event.text,
          })),
        },
        APPROVED: {
          actions: assign({
            approved: ({ context, event }) => [...context.approved, event.text],
          }),
        },
        REJECTED: {
          actions: assign({
            rejected: ({ context, event }) => [...context.rejected, event.reason],
          }),
        },
        CLOSE: {
          target: 'closed',
          actions: sendTo('mod', { type: 'SHUTDOWN' }),
        },
      },
    },
    closed: { type: 'final' },
  },
});
```

