  initial: 'starting',
  context: { apiUrl: '' },
  states: {
    starting: {
      entry: sendTo(({ self }) => self._parent!, { type: 'REQUEST_CONFIG' as const }),
      on: {
        CONFIG: {
          target: 'ready',
          actions: assign({ apiUrl: ({ event }) => event.apiUrl }),
        },
      },
    },
    ready: {
      type: 'final',
    },
  },
});

type ParentEvent = { type: 'REQUEST_CONFIG' };

export const host = setup({
  types: {
    context: {} as { apiUrl: string },
    events: {} as ParentEvent,
  },
  actors: { configurable },
}).createMachine({
  id: 'host',
  context: { apiUrl: 'https://api.example.com' },
  invoke: { id: 'child', src: 'configurable' },
  on: {
    REQUEST_CONFIG: {
      actions: sendTo('child', ({ context }) => ({
        type: 'CONFIG' as const,
        apiUrl: context.apiUrl,
      })),
    },
  },
});
