  types: {
    context: {} as { balance: number; txns: number },
    events: {} as Event,
  },
  actions: {
    applyDeposit: assign({
      balance: ({ context, event }) => {
        if (event.type !== 'DEPOSIT') return context.balance;
        return context.balance + event.amount;
      },
      txns: ({ context }) => context.txns + 1,
    }),
    applyWithdraw: assign({
      balance: ({ context, event }) => {
        if (event.type !== 'WITHDRAW') return context.balance;
        return context.balance - event.amount;
      },
      txns: ({ context }) => context.txns + 1,
    }),
  },
  guards: {
    isPositive: ({ event }) =>
      (event.type === 'DEPOSIT' || event.type === 'WITHDRAW') && event.amount > 0,
    hasFunds: ({ context, event }) =>
      event.type === 'WITHDRAW' && context.balance >= event.amount,
  },
}).createMachine({
  id: 'account',
  initial: 'open',
  context: { balance: 0, txns: 0 },
  states: {
    open: {
      on: {
        DEPOSIT: {
          guard: 'isPositive',
          actions: 'applyDeposit',
        },
        WITHDRAW: {
          guard: 'hasFunds',
          actions: 'applyWithdraw',
        },
      },
    },
  },
});
