A race invokes a promise actor that internally calls `Promise.race` over two endpoints and returns the first successful response. The machine treats this as a single invoke: onDone on the winner, onError if both fail.

```ts
import { setup, assign, fromPromise } from 'xstate';

type Ctx = { value: string | null; error: string | null };
type Ev = { type: 'START' };

export const raceFetch = setup({
  types: {
    context: {} as Ctx,
    events: {} as Ev,
  },
  actors: {
    race: fromPromise<string, void>(async () => {
      const results = await Promise.race([
        fetch('/primary').then((r) => r.text()),
        fetch('/secondary').then((r) => r.text()),
      ]);
      return results;
    }),
  },
}).createMachine({
  id: 'raceFetch',
  initial: 'idle',
  context: { value: null, error: null },
  states: {
    idle: { on: { START: 'racing' } },
    racing: {
      invoke: {
        src: 'race',
        onDone: {
          target: 'done',
          actions: assign({ value: ({ event }) => event.output }),
        },
        onError: {
          target: 'failed',
          actions: assign({
            error: ({ event }) => (event.error as Error).message,
          }),
        },
      },
    },
    done: { type: 'final' },
    failed: {},
  },
});
