import { setup, assign, fromPromise } from 'xstate';

type Event = { name: string; payload: Record<string, string> };
type Ctx = { queue: Event[]; sent: number };
type Ev =
  | { type: 'ENQUEUE'; event: Event }
  | { type: 'FLUSH' };

export const analytics = setup({
  types: {
    context: {} as Ctx,
    events: {} as Ev,
  },
  actors: {
    send: fromPromise<number, { events: Event[] }>(async ({ input }) => {
      const r = await fetch('/collect', {
        method: 'POST',
        body: JSON.stringify(input.events),
      });
      if (!r.ok) throw new Error('collector down');
      return input.events.length;
    }),
  },
  actions: {
    warn: ({ event }) => {
      // eslint-disable-next-line no-console
      console.warn('analytics failed', (event as { error?: unknown }).error);
    },
  },
}).createMachine({
  id: 'analytics',
  initial: 'idle',
  context: { queue: [], sent: 0 },
  states: {
    idle: {
      on: {
        ENQUEUE: {
          actions: assign({
            queue: ({ context, event }) => [...context.queue, event.event],
          }),
        },
        FLUSH: { target: 'sending' },
      },
    },
    sending: {
      invoke: {
        src: 'send',
        input: ({ context }) => ({ events: context.queue }),
        onDone: {
          target: 'idle',
          actions: assign({
            sent: ({ context, event }) => context.sent + event.output,
            queue: () => [],
          }),
        },
        onError: { target: 'idle', actions: 'warn' },
      },
    },
  },
});
